/* Keccak-256 one-shot: out_ptr[0..31] = Keccak256(msg_ptr[0..msg_len-1]). */
fn keccak256_oneshot(msg_ptr: u64, msg_len: u64, out_ptr: u64) -> i32 @export {
    KK256_MP[0] = msg_ptr
    KK256_ML[0] = msg_len
    KK256_OP[0] = out_ptr
    keccak_state_zero(&KK256_STATE as u64)
    keccak_absorb(&KK256_STATE as u64, KK256_MP[0], KK256_ML[0], 0x0000000100000088u64)
    keccak_squeeze(&KK256_STATE as u64, KK256_OP[0], 32u64, 136u32)
    return 0i32
}

