/* Keccak-256 one-shot: out_ptr[0..31] = Keccak256(msg_ptr[0..msg_len-1]).
 * Returns 0 on success or the first non-zero rc from the underlying sponge
 * (KK_E_NULL=-1 on null state/msg, KK_E_BADRATE=-2 on bad rate).
 * All real callers pass validated module-scope scratch -> valid-input rc stays 0. */
fn keccak256_oneshot(msg_ptr: u64, msg_len: u64, out_ptr: u64) -> i32 @export {
    KK256_MP[0] = msg_ptr
    KK256_ML[0] = msg_len
    KK256_OP[0] = out_ptr
    let r0 : i32 = keccak_state_zero(&KK256_STATE as u64)
    if r0 != 0i32 { return r0 }
    let r1 : i32 = keccak_absorb(&KK256_STATE as u64, KK256_MP[0], KK256_ML[0], 0x0000000100000088u64)
    if r1 != 0i32 { return r1 }
    let r2 : i32 = keccak_squeeze(&KK256_STATE as u64, KK256_OP[0], 32u64, 136u32)
    if r2 != 0i32 { return r2 }
    return 0i32
}

