/* KAT: Keccak256("")  = c5d24601...85a470 ; Keccak256("abc") = 4e03657a...12d6c45 ;
 * streaming "abc" (split) == one-shot ; multi-block streaming (150+50, crosses the
 * 136-byte rate boundary) == one-shot.  Negative: null msg_ptr with len>0 -> non-zero
 * rc (keccak_absorb KK_E_NULL=-1 propagated through oneshot).  99 = pass. */
fn keccak256_kat() -> u64 @export {
    /* Negative: null msg with len>0 -> keccak_absorb returns KK_E_NULL; oneshot must propagate. */
    let rneg : i32 = keccak256_oneshot(0u64, 1u64, &KK256_OUT as u64)
    if rneg == 0i32 { return 12u64 }
    keccak256_oneshot(&KK256_MSG as u64, 0u64, &KK256_OUT as u64)
    if KK256_OUT[0] != 0xc5u8 { return 1u64 }

    out_k_memo[0u64] = kmp[0u64]
    let chain_ptr : *u8 = (&MEMOL_CHAIN_IDS as u64 + s * 32u64) as *u8
    /* Best-effort hit-record: out-params are already filled above; a failed emit
     * (e.g. witness hook at capacity) does NOT revoke the valid read result.
     * Mutation paths (ml_admit/ml_mark_stale/ml_revalidate) return ml_emit_event
     * because emit is part of the M6 transparency contract for state changes;
     * a read-path hit-record is audit continuity only -- asymmetry is deliberate. */
    ml_emit_event(MEMOL_EVT_HIT, key, chain_ptr)
    return MEMOL_OK
}
